//DRAW ----------------------------------------
public void draw(){
  
  //Controla la música de las pantallas de menu (desde aquí para no sobre cargar el programa por el uso de loop())
  if(menu == 0 || menu == 2){
    playMenuMusic();
    menuMusicStarted = true;
  }
  
  //Para poder cambiar entre pantallas
  switch(menu){
    
    //MENÚ PRINCIPAL
    case 0:
      mainMenu();
    break;
    
    //JUEGO
    case 1:
    if(!gameOver){
            
    if(menuMusic.isPlaying()){
      menuMusic.pause();
      menuMusicStarted = false;
    }
    
    gameMusic.rate(rate);
    
    if(!gameMusicStarted){
      gameMusic.loop();
      gameMusicStarted = true;
    }
              
    levelUp();
    
    //Cambiamos el fondo y la velocidad de acuerdo con el nivel en el que estemos
    switch(level){
      case 1:
        xMovementVelocity = gamePaused ? 0 : 6; //Modificar para mayor o menor velocidad de juego. Si el juego está pausado la velocidad es 0
        nextLevelMark = 20;
        backgroundOne = backgroundDay;
        backgroundTwo = backgroundDay;
        image(backgroundOne, backgroundOneXPos, -100);
        image(backgroundTwo, backgroundTwoXPos, -100);
        break;
      case 2:
        xMovementVelocity = gamePaused ? 0 : 8;
        nextLevelMark = 15;
        backgroundOne = backgroundAfternoon;
        backgroundTwo = backgroundAfternoon;
        image(backgroundOne, backgroundOneXPos, -100);
        image(backgroundTwo, backgroundTwoXPos, -100);
        break;
      case 3:
        xMovementVelocity = gamePaused ? 0 : 10;
        nextLevelMark = 10;
        backgroundOne = backgroundNight;
        backgroundTwo = backgroundNight;
        image(backgroundOne, backgroundOneXPos, -100);
        image(backgroundTwo, backgroundTwoXPos, -100);
        for(Light light : lights){
          light.turnOn();
        }
        break;
    }
    
    isGameOver();
    
    seagull.display();
       
    if(!gamePaused){
      seagull.gravityBehaviour();
    }
    
    //Movimiento horizontal de las imágenes, a mayor valor, mayor velocidad
    backgroundOneXPos -= xMovementVelocity;
    backgroundTwoXPos -= xMovementVelocity;
    
    //Permite posicionar los fondos uno después del otro, para dar sensación de movimiento con la repetición de la imagen
    if(backgroundOneXPos <= - bgWidth){
      backgroundOneXPos = backgroundTwoXPos + bgWidth;
    }  
    if(backgroundTwoXPos <= - bgWidth){
      backgroundTwoXPos = backgroundOneXPos + bgWidth;
    }

    for(Food food : foods){
      food.display();
      food.move();
      food.updateIcon();
      food.reactivateFood();
      
      float fx = food.imageXPos + food.image.width / 2 + 5; //Ancho
      float fy = food.imageYPos + food.image.height / 2; //Alto
      float frX = (food.image.width + 10) / 2; //Radio X
      float frY = (food.image.height + 10) / 2; //Radio Y
      
      if(collides(seagull, fx, fy, frX, frY)){
        food.collisionBehaviour();
      }
    }
    
    for(Light light : lights){
      light.display();
      light.drawPole();
      light.move();
      light.cooldownBehaviour();
      
      float ox = light.imageXPos + light.image.width / 2 - 10; //Ancho
      float oy = light.imageYPos + light.image.height / 2; //Alto
      float orX = (light.image.width + 10) / 2; //Radio X
      float orY = (light.image.height + 10) / 2; //Radio Y
      
      if(collides(seagull, ox, oy, orX, orY)){
        light.collisionBehaviour();
      }
    }
    
    if (showLevelMessage) {
      currentLevelMessage();
    }
    
    adjustLightsPos();
    adjustFoodPos();
    drawLives();
    printPoints();
  }

  break;
  
  //INSTRUCCIONES
  case 2:
    instructionsMenu();
  break;
  
  //PERDER - GAME OVER
  case 3:
    gameOverMenu();
  break;
  
  //GANAR
  case 4:
    wonMenu();
  break;
  
  }
  
  
}

