//REAJUSTE DE POSICIÓNES DE LUCES Y COMIDA PARA MOVIMIENTO INFINITO

//Reajustar la posición en X de las instancias de las luces de navidad y hacer el efecto de movimiento infinito junto con el fondo
public void adjustLightsPos(){
    
    float maxXPos = -Float.MAX_VALUE;
    
    for(Light l : lights){
      if(l.imageXPos > maxXPos){
        maxXPos = l.imageXPos;
      }
    }
    
    for(Light l : lights){
      if(l.imageXPos + l.image.width < 0){
        l.imageXPos = maxXPos + l.image.width + 200;
      }
    }
}

//Reajustar la posición de la comida para dar la apariencia de que se generan infinitamente
public void adjustFoodPos(){
  
  float maxXPos = -Float.MAX_VALUE;
  
  for(Food food : foods){
    if(food.imageXPos > maxXPos){
      maxXPos = food.imageXPos;
    }
  }
  
  for(Food food : foods){
    if(food.imageXPos + food.image.width < 0){
      food.imageXPos = maxXPos + food.image.width + 260;
    }
  }
  
}

//CONTROLES PERSONAJE
public void keyPressed(){
  if(!gamePaused){
    switch(keyCode){
    case UP:
    seagull.moveUp();    
    break;
    
    case DOWN:
    seagull.isDiving = true;
    seagull.moveDown();
    break;
    
    case LEFT:
    seagull.moveLeft();
    break;
    
    case RIGHT:
    seagull.moveRight();
    break;
    }
  }
}

public void keyReleased(){
  if(!gamePaused){
    if(keyCode == DOWN){
      seagull.isDiving = false;
    }
  }
}

