//Función para controlar la música de las pantallas de los menús Principal, Perder, Ganar e Instrucciones
public void playMenuMusic(){
  if(!menuMusicStarted){
    if(gameMusic.isPlaying()){
      gameMusic.pause();
      gameMusicStarted = false;      
    }
    menuMusic.loop();
    menuMusicStarted = true;
  }
}

//ACCIÓN DE LOS BOTONES ------------------------
public void mouseClicked(){

  // MENÚ PRINCIPAL
  if(menu == 0){
    for(Button button : mainMenuButtons){
      if(button.mouseOver()){
        
        if(buttonClick.isPlaying() == false ){
          buttonClick.play();
        }
        
        switch(button.function){
          case "play":
            menu = 1;
            resetGame();
            startLevelMessage();
            break;

          case "exit":
            exit();
            break;
            
          case "instructions":
            menu = 2;
            instructionsPage = 1;
          break;
        }
      }
    }
  }
  
  //INSTRUCCIONES
  else if(menu == 2){
    for(Button button : instructionsButtons){
      if(button.mouseOver()){
        
        if(buttonClick.isPlaying() == false ){
          buttonClick.play();
        }
        
        switch(button.function){
          case "menu":
            menu = 0;
            break;

          case "back":
          if(instructionsPage > 1){
            instructionsPage -= 1;
          }
          break;
          
          case "next":
          if(instructionsPage < 3){
            instructionsPage += 1;
          }
          break;
        }
      }
    }
  }

  //PANTALLA GAME OVER O WON
  else if(menu == 3 || menu == 4){
    for(Button button : gameOverButtons){
      if(button.mouseOver()){
        
        if(buttonClick.isPlaying() == false ){
          buttonClick.play();
        }
        
        switch(button.function){
          case "play":
            menu = 1;
            resetGame();
            startLevelMessage();
            break;

          case "exit":
            exit();
          break;
        }
      }
    }
  }
}
class Button{
  PImage image;
  float xPos, yPos;
  int imgWidth, imgHeight;
  String function; //función del botón
  boolean wasHovered = false; //Para controlar sonidos
  
  Button(PImage _image, float _xPos, float _yPos, String _function){
    image = _image;
    xPos = _xPos;
    yPos = _yPos;
    function = _function;
    imgWidth = image.width;
    imgHeight = image.height;
  }
  
  public void display(){
    if(mouseOver()){
      image(image, xPos, yPos, imgWidth + 5, imgHeight + 2);
      if(!wasHovered){
        buttonOver.play();
      }
    } else {
      image(image, xPos, yPos, imgWidth, imgHeight);
    } 
    wasHovered = mouseOver();
  }
  
  //Método para comprobar si el cursor está sobre el botón
  public boolean mouseOver(){
    float halfW = imgWidth / 2;
    float halfH = imgHeight / 2;
    boolean xArea = mouseX >= xPos - halfW && mouseX <= xPos + halfW;
    boolean yArea = mouseY >= yPos - halfH && mouseY <= yPos + halfH;
    return xArea && yArea;
  }

}
//Clase Confettti para la pantalla de juego ganado
class Confetti {
  float x, y;
  float speedY;
  float speedX;
  float size;
  float angle;
  float rotationSpeed;
  int col;

  Confetti() {
    reset();
    y = random(-height, 0);
  }

  public void reset() {
    x = random(width);
    y = random(-100, -10);
    speedY = random(2, 6);
    speedX = random(-1.5f, 1.5f);
    size = random(6, 12);
    angle = random(TWO_PI);
    rotationSpeed = random(-0.1f, 0.1f);
    col = color(random(255), random(255), random(255));
  }

  public void update() {
    y += speedY;
    x += speedX;
    angle += rotationSpeed;

    if (y > height + 20) {
      reset();
    }
  }

  public void display() {
    pushMatrix();
    translate(x, y);
    rotate(angle);
    noStroke();
    fill(col);
    rectMode(CENTER);
    rect(0, 0, size, size * 0.6f);
    popMatrix();
  }
}
class Food {
PImage image;
float imageXPos;
float imageYPos;
boolean poisonous;
boolean active = true; //Controlamos si la comida ha sido tocada por la gaviota o no
int timeToRespawn = 5000; // Tiempo en milisegundos para que la comida vuelva a aparecer después de comerla
float deactivationTime; //Controla cuánto tiempo ha pasado desde que se "comió" un alimento

//Alto y ancho de cada imagen (tienen altos y anchos diferentes para mantener la proporción)
int friesW = 51;
int friesH = 62;
int doughnutW = 85;
int doughnutH = 52;
int pizzaW = 56;
int pizzaH = 62;
int bocataW = 70;
int bocataH = 62;
int chiliW = 32;
int chiliH = 81;

Food(PImage _image, float _imageXPos, float _imageYPos){
  image = _image;
  imageXPos = _imageXPos;
  imageYPos = _imageYPos;
  poisonous = (image == chili); //Si la imagen es un chile, poisonous será true
}

public void display(){
  if(active){
    if(image == fries){
      image(image, imageXPos, imageYPos, friesW, friesH);
    } else if (image == doughnut){
      image(image, imageXPos, imageYPos, doughnutW, doughnutH);
    } else if (image == pizza){
      image(image, imageXPos, imageYPos, pizzaW, pizzaH);
    } else if (image == bocata){
      image(image, imageXPos, imageYPos, bocataW, bocataH);
    } else {
      image(image, imageXPos, imageYPos, chiliW, chiliH);
    }
  }
}

//Método para movimiento
public void move(){
  imageXPos -= xMovementVelocity;
}

//Cambiar el icono por otro cuando sale de pantalla para no repetir la secuencia generada en setup()
public void updateIcon(){
  if(imageXPos + image.width < 0){
    image = everyFood[PApplet.parseInt(random(0, everyFood.length))];
    imageXPos -= image.width;
    if(image == chili){
      poisonous = true;   
    } else {
      poisonous = false;
    }
  }
}

//Comportamiento de suma puntos y resta de vidas
public void collisionBehaviour(){
  if(active){
    if(poisonous){
      subtractALife(seagull);
    } else {
      points += 1;
      if(!soundPlayed){
        int randomSfx = PApplet.parseInt(random(0, 2));
        nomSounds[randomSfx].play();
        soundPlayed = true;
      }
    }
  }
  active = false;
  deactivationTime = millis();
  soundPlayed = false;
}

//Hace que la comida reaparezca después de haberla "comido"
public void reactivateFood(){
  if(!active && millis() - deactivationTime >= timeToRespawn){
    active = true;
  }
}

}
